function getEnabledPlatforms(rep) {
    const platforms = ['abuseipdb','otx','dshield','blocklist_de','virustotal'];
    const active = platforms.filter(p => rep[p]?.enabled);
    return active.length ? active.join(', ') : chalk.red('none configured вҖ” run `pnpm run setup`');
}

